
import pandas as pd
import matplotlib.pyplot as plt
import numpy as np

# Read the CSV generated by benchmark.cpp
df = pd.read_csv('benchmark_results.csv')

# Clean column names (in case of extra spaces)
df.columns = df.columns.str.strip()

print(f"Loaded {len(df)} benchmark results from benchmark_results.csv\n")


plt.figure(figsize=(14, 8))

pivot = df.pivot(index='Operation', columns='N', values='Total_ms').fillna(0)

operations = pivot.index
ns = pivot.columns

bar_width = 0.15
x = np.arange(len(operations))

for i, n_val in enumerate(ns):
    plt.bar(x + i * bar_width, pivot[n_val], width=bar_width, label=f'N = {n_val}')


plt.xlabel('Operation')
plt.ylabel('Total Time (ms)')
plt.title('BitBase Benchmark - Total Execution Time by Operation and Scale')
plt.xticks(x + bar_width * (len(ns)-1)/2, operations, rotation=45, ha='right')
plt.legend(title='Number of Rows')
plt.grid(axis='y', alpha=0.3)
plt.tight_layout()
plt.savefig('bitbase_benchmark_total_time.png', dpi=300, bbox_inches='tight')
plt.show()


plt.figure(figsize=(12, 7))

for op in operations:
    subset = df[df['Operation'] == op].sort_values('N')
    plt.plot(subset['N'], subset['Per_op_us'], marker='o', linewidth=2, label=op)

plt.xlabel('Number of Rows (N)')
plt.ylabel('Time per Operation (µs)')
plt.title('BitBase - Per-Operation Latency Scaling')
plt.xscale('log')          
plt.yscale('log')
plt.grid(True, which="both", ls="--", alpha=0.5)
plt.legend(bbox_to_anchor=(1.05, 1), loc='upper left')
plt.tight_layout()
plt.savefig('bitbase_benchmark_per_op_scaling.png', dpi=300, bbox_inches='tight')
plt.show()


df['ops_per_sec'] = 1000000 / df['Per_op_us']   # since per_op_us is microseconds

plt.figure(figsize=(12, 6))
for op in operations:
    subset = df[df['Operation'] == op].sort_values('N')
    plt.plot(subset['N'], subset['ops_per_sec'], marker='s', label=op)

plt.xlabel('Number of Rows (N)')
plt.ylabel('Throughput (operations / second)')
plt.title('BitBase Benchmark - Throughput Scaling')
plt.grid(True, alpha=0.3)
plt.legend()
plt.tight_layout()
plt.savefig('bitbase_benchmark_throughput.png', dpi=300, bbox_inches='tight')
plt.show()


print("   • bitbase_benchmark_total_time.png")
print("   • bitbase_benchmark_per_op_scaling.png")
print("   • bitbase_benchmark_throughput.png")